function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function truncateRaw(text, max) {
  var value = String(text || '');
  return value.length <= max ? value : value.slice(0, max - 1) + '\u2026';
}

var item = $input.first().json || {};
var staticData = $getWorkflowStaticData('global');
var isDbError = !!(item.error && typeof item.error === 'object' && item.error.message);

var tableSizeThresholdBytes = 50 * 1024 * 1024;

if (isDbError) {
  return [{
    json: {
      report: '\u{1F534} <b>DATA RETENTION \u2014 DB ERROR</b>\n\nCleanup query failed.\n\n<b>Error:</b> <code>' + htmlEscape(truncateRaw(String(item.error.message), 500)) + '</code>',
      isDbError: true,
      isLimitHit: false,
      deletedEvents: 0,
      totalEvents: 0,
      eventsTableSize: 'unknown',
      eventsTableSizeBytes: 0,
      eventsIndexSize: 'unknown',
      eventsIndexSizeBytes: 0,
      staleCircuitReset: false,
      schemaVersionPresent: false,
      expectedTablesFound: 0,
      schemaOk: false,
      tableSizeWarning: false,
      indexBloatWarning: false,
      shouldNotify: true,
      notifyReason: 'db_error'
    }
  }];
}

var deletedEvents = parseInt(item.deleted_events_count, 10) || 0;
var staleCircuitReset = item.stale_circuit_reset === true || item.stale_circuit_reset === 't';
var isLimitHit = deletedEvents >= 1000;
var totalEvents = parseInt(item.total_events, 10) || 0;
var eventsTableSize = item.events_table_size || 'unknown';
var eventsTableSizeBytes = parseInt(item.events_table_size_bytes, 10) || 0;
var eventsIndexSize = item.events_index_size || 'unknown';
var eventsIndexSizeBytes = parseInt(item.events_index_size_bytes, 10) || 0;
var schemaVersionPresent = (parseInt(item.schema_version_present, 10) || 0) > 0;
var expectedTablesFound = parseInt(item.expected_tables_found, 10) || 0;
var schemaOk = schemaVersionPresent && expectedTablesFound === 3;

var tableSizeWarning = eventsTableSizeBytes > tableSizeThresholdBytes;
var indexBloatWarning = eventsIndexSizeBytes > tableSizeThresholdBytes;

var now = Date.now();
var lastReportAt = staticData.lastRetentionReportAt || 0;
var daysSinceLastReport = (now - lastReportAt) / (1000 * 60 * 60 * 24);
var weeklyReportDue = daysSinceLastReport >= 7;

var shouldNotify = false;
var notifyReason = 'routine_silent';

if (!schemaOk) { shouldNotify = true; notifyReason = 'schema_drift'; }
else if (isLimitHit) { shouldNotify = true; notifyReason = 'limit_hit'; }
else if (staleCircuitReset) { shouldNotify = true; notifyReason = 'stale_circuit_reset'; }
else if (tableSizeWarning) { shouldNotify = true; notifyReason = 'table_size_warning'; }
else if (indexBloatWarning) { shouldNotify = true; notifyReason = 'index_bloat_warning'; }
else if (weeklyReportDue) { shouldNotify = true; notifyReason = 'weekly_summary'; }

var report = '\u{1F9F9} <b>DATA RETENTION REPORT \u2014 V1 Lean</b>\n\n'
  + '<b>Deleted Events (90d):</b> ' + deletedEvents + '\n'
  + '<b>Remaining Events:</b> ' + totalEvents + '\n'
  + '<b>Events Table Size:</b> ' + eventsTableSize + '\n'
  + '<b>Events Index Size:</b> ' + eventsIndexSize + '\n'
  + '<b>Schema:</b> ' + (schemaOk ? '\u2705 v1_lean present, 3/3 tables' : '\u26A0\uFE0F check needed \u2014 version: ' + (schemaVersionPresent ? 'yes' : 'no') + ', tables: ' + expectedTablesFound + '/3');

if (staleCircuitReset) {
  report += '\n\n\u26A0\uFE0F <b>STALE CIRCUIT RESET:</b> Circuit was open for &gt;1 hour with no new errors. Auto-reset to closed.';
}

if (isLimitHit) {
  report += '\n\n\u26A0\uFE0F <b>LIMIT HIT:</b> Events table hit the 1000-row deletion cap. Run retention again if backlog persists.';
}

if (tableSizeWarning) {
  report += '\n\n\u26A0\uFE0F <b>TABLE SIZE WARNING:</b> supervisor_events is ' + eventsTableSize + ' (threshold: 50 MB).';
}

if (indexBloatWarning) {
  report += '\n\n\u26A0\uFE0F <b>INDEX BLOAT WARNING:</b> supervisor_events indexes are ' + eventsIndexSize + '. Consider running REINDEX.';
}

if (weeklyReportDue && !staleCircuitReset && !isLimitHit && !tableSizeWarning && !indexBloatWarning && schemaOk) {
  report += '\n\n\u{1F4C5} <i>Weekly scheduled report \u2014 no issues detected.</i>';
}

return [{
  json: {
    report: report,
    isDbError: false,
    isLimitHit: isLimitHit,
    deletedEvents: deletedEvents,
    totalEvents: totalEvents,
    eventsTableSize: eventsTableSize,
    eventsTableSizeBytes: eventsTableSizeBytes,
    eventsIndexSize: eventsIndexSize,
    eventsIndexSizeBytes: eventsIndexSizeBytes,
    staleCircuitReset: staleCircuitReset,
    schemaVersionPresent: schemaVersionPresent,
    expectedTablesFound: expectedTablesFound,
    schemaOk: schemaOk,
    tableSizeWarning: tableSizeWarning,
    indexBloatWarning: indexBloatWarning,
    shouldNotify: shouldNotify,
    notifyReason: notifyReason
  }
}];

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function truncateRaw(text, max) {
  var value = String(text || '');
  return value.length <= max ? value : value.slice(0, max - 1) + '\u2026';
}

function clampTelegramHtml(value, max) {
  max = max || 3900;
  var s = String(value || '');
  if (s.length <= max) return s;
  var note = '\n\n\u26A0\uFE0F <i>Message truncated</i>';
  return s.substring(0, max - note.length) + note;
}

function formatTimestamp() {
  return new Date().toLocaleString('en-PH', {
    timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric',
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
  });
}

var item = $input.first().json || {};
var evalData = (function() { try { return $('Evaluate Cleanup').first().json || {}; } catch(e) { return {}; } })();

var report = evalData.report || '\u{1F9F9} <b>DATA RETENTION REPORT</b>\n\nNo cleanup report was generated.';
var analyzeError = !!(item.error && typeof item.error === 'object' && item.error.message);

if (analyzeError) {
  report += '\n\n\u26A0\uFE0F <b>ANALYZE FAILED:</b> <code>' + htmlEscape(truncateRaw(String(item.error.message), 500)) + '</code>';
} else {
  report += '\n\n\u2705 <b>ANALYZE:</b> completed successfully.';
}

report += '\n\n<b>Timestamp:</b> ' + formatTimestamp();

var shouldNotify = evalData.shouldNotify || false;
var notifyReason = evalData.notifyReason || 'routine_silent';

if (analyzeError && !shouldNotify) {
  shouldNotify = true;
  notifyReason = 'analyze_failed';
}

report = clampTelegramHtml(report);

return [{
  json: {
    ...evalData,
    report: report,
    analyzeOk: !analyzeError,
    analyzeErrorMessage: analyzeError ? item.error.message : '',
    shouldNotify: shouldNotify,
    notifyReason: notifyReason
  }
}];

var staticData = $getWorkflowStaticData('global');
var evalData = (function() {
  try { return $('Check Analyze Result').first().json || {}; } catch(e) { return {}; }
})();

var tgResult = (function() {
  try { return $('Telegram (Retention Report)').first().json; } catch(e) { return null; }
})();
var delivered = tgResult && !!tgResult.message_id;

if (evalData.shouldNotify && delivered) {
  staticData.lastRetentionReportAt = Date.now();
}

return [{ json: { done: true, notified: evalData.shouldNotify || false, delivered: !!delivered, notifyReason: evalData.notifyReason || 'silent' } }];
